1	export interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	export interface QuoteInput {
8	  items: QuoteItem[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BLOCK_OF_3_PREMIUM = 60;
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	export function quote(input: QuoteInput): number {
30	  let policyBase = 0;
31	
32	  const itemTypeCounts: Record<string, number> = {};
33	  for (const item of input.items) {
34	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
35	  }
36	
37	  for (const [type, count] of Object.entries(itemTypeCounts)) {
38	    if (count === 3) {
39	      policyBase += BLOCK_OF_3_PREMIUM;
40	    } else {
41	      policyBase += count * BASE_PREMIUM[type];
42	    }
43	  }
44	
45	  let itemSurcharges = 0;
46	  for (const item of input.items) {
47	    const itemBase = BASE_PREMIUM[item.type];
48	    if (item.cursed) {
49	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
50	    }
51	    if (item.enchantment !== undefined && item.enchantment >= 5) {
52	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
53	    }
54	  }
55	
56	  const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
57	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
58	  const policyPremium = policyBase + itemSurcharges - loyaltyDiscount + firstInsuranceSurcharge;
59	  return Math.ceil(policyPremium + PROCESSING_FEE);
60	}
